// Build /public/llms.txt — the short overview that AI / LLM crawlers fetch
// first. Most sections are hand-authored constants; "Featured analyses" is
// generated from /public/articles/index.json so a newly published article
// shows up here automatically, without an extra hand-edit step.
//
// The companion /public/llms-full.txt and /public/llms-full.en.txt corpora
// are generated by ./buildFull.ts; the entries below link to them.

import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const PROJECT_ROOT = path.resolve(__dirname, "../..");
const PUBLIC = path.join(PROJECT_ROOT, "public");
const SITE_URL = "https://electionsbg.com";

type ArticleMeta = {
  slug: string;
  election?: string;
  publishedAt: string;
  category?: string;
  topics?: string[];
  title: { bg: string; en: string };
  summary: { bg: string; en: string };
  /** Editorial draft — kept out of the llms index, prerender, and sitemap.
   *  Drafts only surface on the Vite dev server. */
  draft?: boolean;
};

